#include <stdio.h>
#include <omp.h>

int main() {
    int counter = 0;

    // INCORRECT: Data race on counter
    #pragma omp parallel num_threads(8)
    {
        for (int j = 0; j < 1000; j++) {
            counter++; // Race: read-modify-write not atomic
        }
    }

    printf("Counter: %d (expected: 8000)\n", counter);
    // Output is non-deterministic, typically << 8000

    return 0;
}

#include <stdio.h>
#include <omp.h>

int main() {
    int counter = 0;

    // CORRECT: Using reduction to combine results
    #pragma omp parallel for reduction(+:counter) num_threads(8)
    for (int j = 0; j < 8000; j++) {
        counter++; // Each thread has private counter, initialized to 0
    }
    // At end, runtime combines: counter = counter_t1 + counter_t2 + ... + counter_t8

    printf("Counter: %d (expected: 8000)\n", counter);
    // Output: 8000 (deterministic)

    return 0;
}

#include <stdio.h>
#include <omp.h>

int main() {
    int initial = 100;
    int result = 0;

    // firstprivate: each thread gets copy initialized to 100
    // lastprivate: result gets value from last iteration (i=9)
    #pragma omp parallel for firstprivate(initial) lastprivate(result)
    for (int i = 0; i < 10; i++) {
        initial = initial + i;  // Each thread's initial starts at 100
        result = initial * 2;   // Last iteration: 100+9=109, result=218
        printf("Thread %d: i=%d, initial=%d, result=%d\n", 
               omp_get_thread_num(), i, initial, result);
    }

    printf("\nAfter parallel region:\n");
    printf("initial (original): %d (unchanged by firstprivate)\n", initial);
    printf("result (from lastprivate): %d\n", result);

    return 0;
}
